                } else if (x11 < x21 || (x11 == x21 && x12 < x22)) {
                    right1++
                    if (right1 >= xList1.size) {
                        left1++
                        right1 = left1 + 1
                    }
                } else {
                    right2++
                    if (right2 >= xList2.size) {
                        left2++
                        right2 = left2 + 1
                    }
                }
            }

            // The number of trapezoids is C(m, 2) * C(n, 2) - count, but not sure
            // Actually, the number of trapezoids is combinations of two pairs from xList1 and xList2
            // minus the count of overlapping pairs (which form parallelograms)
            val m = xList1.size.toLong()
            val n = xList2.size.toLong()
            val totalPairs = (m * (m - 1) / 2) * (n * (n - 1) / 2)
            result = (result + totalPairs - count) % MOD
        }
    }

    return result
}
