        for (j in i + 1 until yList.size) {
            val y2 = yList[j]
            val xs2 = yToXs[y2]!!
            if (xs2.size < 2) continue

            // Find all pairs of x-coordinates that are common between y1 and y2
            val commonXs = mutableListOf<Long>()
            var p1 = 0
            var p2 = 0
            while (p1 < xs1.size && p2 < xs2.size) {
                when {
                    xs1[p1] == xs2[p2] -> {
                        commonXs.add(xs1[p1])
                        p1++
                        p2++
                    }
                    xs1[p1] < xs2[p2] -> p1++
                    else -> p2++
                }
