            if (commonXs.size >= 2) {
                val k = commonXs.size
                // The number of ways to choose 2 common x-coordinates is C(k, 2)
                val ways = k.toLong() * (k.toLong() - 1) / 2
                // The number of ways to choose other two points is C(xs1.size - k, 2) + C(xs2.size - k, 2) + (xs1.size - k) * (xs2.size - k)
